import { Linking } from 'react-native';
import { NavigationActions } from '@react-navigation/native';

const handleDeepLink = async (url) => {
  const urlParts = url.split('/');
  const scheme = urlParts[0];
  const screenName = urlParts[1];

  if (scheme === 'myapp') {
    switch (screenName) {
      case 'profile':
        const profileId = urlParts[urlParts.length - 1];
        NavigationActions.navigate({ name: 'Profile', params: { id: profileId } });
        break;
      case 'payment':
        const paymentType = urlParts[urlParts.length - 2];
        if (paymentType === 'confirm') {
          NavigationActions.navigate({ name: 'PaymentConfirmation' });
        }
        break;
      default:
        console.log('Unknown screen');
    }
  }
};

Linking.addEventListener('url', (event) => {
  handleDeepLink(event.url);
});

export const configure = () => {
  Linking.openURL('myapp://profile/123').catch((err) => err);
};